content.text:
Struktur təyin etmək üçün aşağıdakı sintaksisdən istifadə edilir:
struct StructureName {
  data_type member1;
  data_type member2;
};
- **StructureName**: Strukturun adı.
- **member1, member2**: Strukturun üzvləri (dəyişənlər).
Struktur təyin edildikdən sonra onun obyektləri yaradılaraq üzvlərinə müraciət edilir: structure_object.member.

content.code:
#include <iostream>
#include <string>

struct Student {
  std::string name;
  int age;
  double grade;
};

int main() {
  Student student;
  student.name = "Ali";
  student.age = 20;
  student.grade = 85.5;
  std::cout << "Name: " << student.name << std::endl;
  std::cout << "Age: " << student.age << std::endl;
  std::cout << "Grade: " << student.grade << std::endl;
  return 0;
}
// Output:
// Name: Ali
// Age: 20
// Grade: 85.5

#include <iostream>
#include <string>

struct Student {
  std::string name;
  int age;
  double grade;
};

void printStudent(const Student& s) {
  std::cout << "Name: " << s.name << std::endl;
  std::cout << "Age: " << s.age << std::endl;
  std::cout << "Grade: " << s.grade << std::endl;
}

int main() {
  Student student;
  student.name = "Veli";
  student.age = 22;
  student.grade = 90.0;
  printStudent(student);
  return 0;
}
// Output:
// Name: Veli
// Age: 22
// Grade: 90

#include <iostream>
#include <string>

struct Student {
  std::string name;
  int age;
  double grade;
};

int main() {
  Student* ptr = new Student;
  ptr->name = "Ayşe";
  ptr->age = 21;
  ptr->grade = 88.5;
  std::cout << "Name: " << ptr->name << std::endl;
  std::cout << "Age: " << ptr->age << std::endl;
  delete ptr;
  return 0;
}
// Output:
// Name: Ayşe
// Age: 21
// Grade: 88.5

